import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r,o as i,c as t,a as e,b as o,d as l,e as c}from"./app-8a691f6d.js";const n={},s=c('<h1 id="java-基础面试" tabindex="-1"><a class="header-anchor" href="#java-基础面试" aria-hidden="true">#</a> Java 基础面试</h1><h2 id="并发简介" tabindex="-1"><a class="header-anchor" href="#并发简介" aria-hidden="true">#</a> 并发简介</h2><h3 id="什么是进程-什么是线程-进程和线程的区别" tabindex="-1"><a class="header-anchor" href="#什么是进程-什么是线程-进程和线程的区别" aria-hidden="true">#</a> 什么是进程？什么是线程？进程和线程的区别？</h3><ul><li>什么是进程？ <ul><li>简言之，进程可视为一个正在运行的程序。</li><li>进程是具有一定独立功能的程序关于某个数据集合上的一次运行活动。进程是操作系统进行资源分配的基本单位。</li></ul></li><li>什么是线程？ <ul><li>线程是操作系统进行调度的基本单位。</li></ul></li><li>进程 vs. 线程 <ul><li>一个程序至少有一个进程，一个进程至少有一个线程。</li><li>线程比进程划分更细，所以执行开销更小，并发性更高。</li><li>进程是一个实体，拥有独立的资源；而同一个进程中的多个线程共享进程的资源。</li></ul></li></ul><h3 id="并发-多线程-编程的好处是什么" tabindex="-1"><a class="header-anchor" href="#并发-多线程-编程的好处是什么" aria-hidden="true">#</a> 并发（多线程）编程的好处是什么？</h3><ul><li>更有效率的利用多处理器核心</li><li>更快的响应时间</li><li>更好的编程模型</li></ul><h3 id="并发一定比串行更快吗" tabindex="-1"><a class="header-anchor" href="#并发一定比串行更快吗" aria-hidden="true">#</a> 并发一定比串行更快吗？</h3><p>答：否。</p><p>要点：<strong>创建线程和线程上下文切换有一定开销</strong>。</p><p>说明：即使是单核处理器也支持多线程。CPU 通过给每个线程分配时间切片的算法来循环执行任务，当前任务执行一个时间片后会切换到下一个任务。但是，在切换前会保持上一个任务的状态，以便下次切换回这个任务时，可以再加载这个任务的状态。所以<strong>任务从保存到再加载的过程就是一次上下文切换</strong>。</p><p>引申</p><ul><li>如何减少上下文切换？ <ul><li>尽量少用锁</li><li>CAS 算法</li><li>线程数要合理</li><li>协程：在单线程中实现多任务调度，并在单线程中维持多个任务的切换</li></ul></li></ul><h3 id="如何让正在运行的线程暂停一段时间" tabindex="-1"><a class="header-anchor" href="#如何让正在运行的线程暂停一段时间" aria-hidden="true">#</a> 如何让正在运行的线程暂停一段时间？</h3><p>我们可以使用 <code>Thread</code> 类的 Sleep() 方法让线程暂停一段时间。</p><p>需要注意的是，这并不会让线程终止，一旦从休眠中唤醒线程，线程的状态将会被改变为 Runnable，并且根据线程调度，它将得到执行。</p><h3 id="什么是线程调度器-thread-scheduler-和时间分片-time-slicing" tabindex="-1"><a class="header-anchor" href="#什么是线程调度器-thread-scheduler-和时间分片-time-slicing" aria-hidden="true">#</a> 什么是线程调度器(Thread Scheduler)和时间分片(Time Slicing)？</h3><p>线程调度器是一个操作系统服务，它负责为 <code>Runnable</code> 状态的线程分配 CPU 时间。一旦我们创建一个线程并启动它，它的执行便依赖于线程调度器的实现。</p><p>时间分片是指将可用的 CPU 时间分配给可用的 <code>Runnable</code> 线程的过程。</p><p>分配 CPU 时间可以基于线程优先级或者线程等待的时间。线程调度并不受到 Java 虚拟机控制，所以由应用程序来控制它是更好的选择（也就是说不要让你的程序依赖于线程的优先级）。</p><h3 id="在多线程中-什么是上下文切换-context-switching" tabindex="-1"><a class="header-anchor" href="#在多线程中-什么是上下文切换-context-switching" aria-hidden="true">#</a> 在多线程中，什么是上下文切换(context-switching)？</h3><p>上下文切换是存储和恢复 CPU 状态的过程，它使得线程执行能够从中断点恢复执行。上下文切换是多任务操作系统和多线程环境的基本特征。</p><h3 id="如何确保线程安全" tabindex="-1"><a class="header-anchor" href="#如何确保线程安全" aria-hidden="true">#</a> 如何确保线程安全？</h3><ul><li>原子类(atomic concurrent classes)</li><li>锁</li><li><code>volatile</code> 关键字</li><li>不变类和线程安全类</li></ul><h3 id="什么是死锁-deadlock-如何分析和避免死锁" tabindex="-1"><a class="header-anchor" href="#什么是死锁-deadlock-如何分析和避免死锁" aria-hidden="true">#</a> 什么是死锁(Deadlock)？如何分析和避免死锁？</h3><p>死锁是指两个以上的线程永远相互阻塞的情况，这种情况产生至少需要两个以上的线程和两个以上的资源。</p><p>分析死锁，我们需要查看 Java 应用程序的线程转储。我们需要找出那些状态为 BLOCKED 的线程和他们等待的资源。每个资源都有一个唯一的 id，用这个 id 我们可以找出哪些线程已经拥有了它的对象锁。</p><p>避免嵌套锁，只在需要的地方使用锁和避免无限期等待是避免死锁的通常办法。</p><h2 id="线程基础" tabindex="-1"><a class="header-anchor" href="#线程基础" aria-hidden="true">#</a> 线程基础</h2><h3 id="java-线程生命周期中有哪些状态-各状态之间如何切换" tabindex="-1"><a class="header-anchor" href="#java-线程生命周期中有哪些状态-各状态之间如何切换" aria-hidden="true">#</a> Java 线程生命周期中有哪些状态？各状态之间如何切换？</h3><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/cs/java/javacore/concurrent/java-thread_1.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p><code>java.lang.Thread.State</code> 中定义了 <strong>6</strong> 种不同的线程状态，在给定的一个时刻，线程只能处于其中的一个状态。</p><p>以下是各状态的说明，以及状态间的联系：</p><ul><li><strong>开始（New）</strong> - 还没有调用 <code>start()</code> 方法的线程处于此状态。</li><li><strong>可运行（Runnable）</strong> - 已经调用了 <code>start()</code> 方法的线程状态。此状态意味着，线程已经准备好了，一旦被线程调度器分配了 CPU 时间片，就可以运行线程。</li><li><strong>阻塞（Blocked）</strong> - 阻塞状态。线程阻塞的线程状态等待监视器锁定。处于阻塞状态的线程正在等待监视器锁定，以便在调用 <code>Object.wait()</code> 之后输入同步块/方法或重新输入同步块/方法。</li><li><strong>等待（Waiting）</strong> - 等待状态。一个线程处于等待状态，是由于执行了 3 个方法中的任意方法： <ul><li><code>Object.wait()</code></li><li><code>Thread.join()</code></li><li><code>LockSupport.park()</code></li></ul></li><li><strong>定时等待（Timed waiting）</strong> - 等待指定时间的状态。一个线程处于定时等待状态，是由于执行了以下方法中的任意方法： <ul><li><code>Thread.sleep(sleeptime)</code></li><li><code>Object.wait(timeout)</code></li><li><code>Thread.join(timeout)</code></li><li><code>LockSupport.parkNanos(timeout)</code></li><li><code>LockSupport.parkUntil(timeout)</code></li></ul></li><li><strong>终止(Terminated)</strong> - 线程 <code>run()</code> 方法执行结束，或者因异常退出了 <code>run()</code> 方法，则该线程结束生命周期。死亡的线程不可再次复生。</li></ul>',33),h={href:"https://www.w3resource.com/java-tutorial/java-threadclass-methods-and-threadstates.php",target:"_blank",rel:"noopener noreferrer"},p=e("code",null,"Thread",-1),u=e("code",null,"Thread",-1),g=e("br",null,null,-1),b={href:"https://blog.csdn.net/pange1991/article/details/53860651",target:"_blank",rel:"noopener noreferrer"},f=c('<h3 id="创建线程有哪些方式-这些方法各自利弊是什么" tabindex="-1"><a class="header-anchor" href="#创建线程有哪些方式-这些方法各自利弊是什么" aria-hidden="true">#</a> 创建线程有哪些方式？这些方法各自利弊是什么？</h3><p>创建线程主要有三种方式：</p><p><strong>1. 继承 <code>Thread</code> 类</strong></p><ul><li>定义 <code>Thread</code> 类的子类，并重写该类的 <code>run()</code> 方法，该 <code>run()</code> 方法的方法体就代表了线程要完成的任务。因此把 <code>run()</code> 方法称为执行体。</li><li>创建 <code>Thread</code> 子类的实例，即创建了线程对象。</li><li>调用线程对象的 <code>start()</code> 方法来启动该线程。</li></ul><p><strong>2. 实现 <code>Runnable</code> 接口</strong></p><ul><li>定义 <code>Runnable</code> 接口的实现类，并重写该接口的 <code>run()</code> 方法，该 <code>run()</code> 方法的方法体同样是该线程的线程执行体。</li><li>创建 <code>Runnable</code> 实现类的实例，并以此实例作为 <code>Thread</code> 对象，该 <code>Thread</code> 对象才是真正的线程对象。</li><li>调用线程对象的 start() 方法来启动该线程。</li></ul><p><strong>3. 通过 <code>Callable</code> 接口和 <code>Future</code> 接口</strong></p><ul><li>创建 <code>Callable</code> 接口的实现类，并实现 <code>call()</code> 方法，该 <code>call()</code> 方法将作为线程执行体，并且有返回值。</li><li>创建 <code>Callable</code> 实现类的实例，使用 <code>FutureTask</code> 类来包装 <code>Callable</code> 对象，该 <code>FutureTask</code> 对象封装了该 <code>Callable</code> 对象的 <code>call()</code> 方法的返回值。</li><li>使用 <code>FutureTask</code> 对象作为 <code>Thread</code> 对象的 target 创建并启动新线程。</li><li>调用 <code>FutureTask</code> 对象的 <code>get()</code> 方法来获得子线程执行结束后的返回值</li></ul><p>三种创建线程方式对比</p><ul><li>实现 <code>Runnable</code> 接口优于继承 <code>Thread</code> 类，因为根据开放封闭原则——实现接口更便于扩展；</li><li>实现 <code>Runnable</code> 接口的线程没有返回值；而使用 <code>Callable</code> / <code>Future</code> 方式可以让线程有返回值。</li></ul>',10),v={href:"https://blog.csdn.net/longshengguoji/article/details/41126119",target:"_blank",rel:"noopener noreferrer"},y=c('<h3 id="什么是-callable-和-future-什么是-futuretask" tabindex="-1"><a class="header-anchor" href="#什么是-callable-和-future-什么是-futuretask" aria-hidden="true">#</a> 什么是 <code>Callable</code> 和 <code>Future</code>？什么是 <code>FutureTask</code>？</h3><p><strong>什么是 <code>Callable</code> 和 <code>Future</code>？</strong></p><p>Java 5 在 concurrency 包中引入了 <code>Callable</code> 接口，它和 <code>Runnable</code> 接口很相似，但它可以返回一个对象或者抛出一个异常。</p><p><code>Callable</code> 接口使用泛型去定义它的返回类型。<code>Executors</code> 类提供了一些有用的方法去在线程池中执行 <code>Callable</code> 内的任务。由于 <code>Callable</code> 任务是并行的，我们必须等待它返回的结果。<code>Future</code> 对象为我们解决了这个问题。在线程池提交 <code>Callable</code> 任务后返回了一个 <code>Future</code> 对象，使用它我们可以知道 <code>Callable</code> 任务的状态和得到 <code>Callable</code> 返回的执行结果。<code>Future</code> 提供了 <code>get()</code> 方法让我们可以等待 <code>Callable</code> 结束并获取它的执行结果。</p><p><strong>什么是 <code>FutureTask</code>？</strong></p><p><code>FutureTask</code> 是 <code>Future</code> 的一个基础实现，我们可以将它同 <code>Executors</code> 使用处理异步任务。通常我们不需要使用 <code>FutureTask</code> 类，单当我们打算重写 <code>Future</code> 接口的一些方法并保持原来基础的实现是，它就变得非常有用。我们可以仅仅继承于它并重写我们需要的方法。阅读 Java <code>FutureTask</code> 例子，学习如何使用它。</p>',6),_={href:"http://www.cnblogs.com/dolphin0520/p/3949310.html",target:"_blank",rel:"noopener noreferrer"},k=c('<h3 id="start-和-run-有什么区别-可以直接调用-thread-类的-run-方法么" tabindex="-1"><a class="header-anchor" href="#start-和-run-有什么区别-可以直接调用-thread-类的-run-方法么" aria-hidden="true">#</a> <code>start()</code> 和 <code>run()</code> 有什么区别？可以直接调用 <code>Thread</code> 类的 <code>run()</code> 方法么？</h3><ul><li><code>run()</code> 方法是线程的执行体。</li><li><code>start()</code> 方法负责启动线程，然后 JVM 会让这个线程去执行 <code>run()</code> 方法。</li></ul><p>可以直接调用 <code>Thread</code> 类的 <code>run()</code> 方法么？</p><ul><li>可以。但是如果直接调用 <code>Thread</code> 的 <code>run()</code> 方法，它的行为就会和普通的方法一样。</li><li>为了在新的线程中执行我们的代码，必须使用 <code>start()</code> 方法。</li></ul><h3 id="sleep-、yield-、join-方法有什么区别-为什么-sleep-和-yield-方法是静态-static-的" tabindex="-1"><a class="header-anchor" href="#sleep-、yield-、join-方法有什么区别-为什么-sleep-和-yield-方法是静态-static-的" aria-hidden="true">#</a> <code>sleep()</code>、<code>yield()</code>、<code>join()</code> 方法有什么区别？为什么 <code>sleep()</code> 和 <code>yield()</code> 方法是静态（static）的？</h3><p><strong><code>yield()</code></strong></p><ul><li><code>yield()</code> 方法可以让当前正在执行的线程暂停，但它不会阻塞该线程，它只是将该线程从 <strong>Running</strong> 状态转入 <code>Runnable</code> 状态。</li><li>当某个线程调用了 <code>yield()</code> 方法暂停之后，只有优先级与当前线程相同，或者优先级比当前线程更高的处于就绪状态的线程才会获得执行的机会。</li></ul><p><strong><code>sleep()</code></strong></p><ul><li><code>sleep()</code> 方法需要指定等待的时间，它可以让当前正在执行的线程在指定的时间内暂停执行，进入 <strong>Blocked</strong> 状态。</li><li>该方法既可以让其他同优先级或者高优先级的线程得到执行的机会，也可以让低优先级的线程得到执行机会。</li><li>但是，<code>sleep()</code> 方法不会释放“锁标志”，也就是说如果有 <code>synchronized</code> 同步块，其他线程仍然不能访问共享数据。</li></ul><p><strong><code>join()</code></strong></p><ul><li><code>join()</code> 方法会使当前线程转入 <strong>Blocked</strong> 状态，等待调用 <code>join()</code> 方法的线程结束后才能继续执行。</li></ul><p><strong>为什么 <code>sleep()</code> 和 <code>yield()</code> 方法是静态（static）的？</strong></p><ul><li><code>Thread</code> 类的 <code>sleep()</code> 和 <code>yield()</code> 方法将处理 <strong>Running</strong> 状态的线程。所以在其他处于非 <strong>Running</strong> 状态的线程上执行这两个方法是没有意义的。这就是为什么这些方法是静态的。它们可以在当前正在执行的线程中工作，并避免程序员错误的认为可以在其他非运行线程调用这些方法。</li></ul>',13),m={href:"http://www.importnew.com/14958.html",target:"_blank",rel:"noopener noreferrer"},C=e("br",null,null,-1),T={href:"https://blog.csdn.net/xiangwanpeng/article/details/54972952",target:"_blank",rel:"noopener noreferrer"},J=c('<h3 id="java-的线程优先级如何控制-高优先级的-java-线程一定先执行吗" tabindex="-1"><a class="header-anchor" href="#java-的线程优先级如何控制-高优先级的-java-线程一定先执行吗" aria-hidden="true">#</a> Java 的线程优先级如何控制？高优先级的 Java 线程一定先执行吗？</h3><p><strong>Java 中的线程优先级如何控制</strong></p><ul><li>Java 中的线程优先级的范围是 <code>[1,10]</code>，一般来说，高优先级的线程在运行时会具有优先权。可以通过 <code>thread.setPriority(Thread.MAX_PRIORITY)</code> 的方式设置，默认优先级为 <code>5</code>。</li></ul><p><strong>高优先级的 Java 线程一定先执行吗</strong></p><ul><li>即使设置了线程的优先级，也<strong>无法保证高优先级的线程一定先执行</strong>。</li><li>原因：这是因为 <strong>Java 线程优先级依赖于操作系统的支持</strong>，然而，不同的操作系统支持的线程优先级并不相同，不能很好的和 Java 中线程优先级一一对应。</li><li>结论：Java 线程优先级控制并不可靠。</li></ul><h3 id="什么是守护线程-为什么要用守护线程-如何创建守护线程" tabindex="-1"><a class="header-anchor" href="#什么是守护线程-为什么要用守护线程-如何创建守护线程" aria-hidden="true">#</a> 什么是守护线程？为什么要用守护线程？如何创建守护线程？</h3><p><strong>什么是守护线程</strong></p><ul><li>守护线程（Daemon Thread）是在后台执行并且不会阻止 JVM 终止的线程。</li><li>与守护线程（Daemon Thread）相反的，叫用户线程（User Thread），也就是非守护线程。</li></ul><p><strong>为什么要用守护线程</strong></p><ul><li>守护线程的优先级比较低，用于为系统中的其它对象和线程提供服务。典型的应用就是垃圾回收器。</li></ul><p><strong>如何创建守护线程</strong></p><ul><li>使用 <code>thread.setDaemon(true)</code> 可以设置 thread 线程为守护线程。</li><li>注意点： <ul><li>正在运行的用户线程无法设置为守护线程，所以 <code>thread.setDaemon(true)</code> 必须在 <code>thread.start()</code> 之前设置，否则会抛出 <code>llegalThreadStateException</code> 异常；</li><li>一个守护线程创建的子线程依然是守护线程。</li><li>不要认为所有的应用都可以分配给守护线程来进行服务，比如读写操作或者计算逻辑。</li></ul></li></ul>',12),x={href:"https://blog.csdn.net/shimiso/article/details/8964414",target:"_blank",rel:"noopener noreferrer"},w=e("h3",{id:"线程间是如何通信的",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#线程间是如何通信的","aria-hidden":"true"},"#"),o(" 线程间是如何通信的？")],-1),j=e("p",null,[o("当线程间是可以共享资源时，线程间通信是协调它们的重要的手段。"),e("code",null,"Object"),o(" 类中 "),e("code",null,"wait()"),o(", "),e("code",null,"notify()"),o(" 和 "),e("code",null,"notifyAll()"),o(" 方法可以用于线程间通信关于资源的锁的状态。")],-1),A={href:"http://www.cnblogs.com/dolphin0520/p/3920385.html",target:"_blank",rel:"noopener noreferrer"},z=c('<h3 id="为什么线程通信的方法-wait-notify-和-notifyall-被定义在-object-类里" tabindex="-1"><a class="header-anchor" href="#为什么线程通信的方法-wait-notify-和-notifyall-被定义在-object-类里" aria-hidden="true">#</a> 为什么线程通信的方法 <code>wait()</code>, <code>notify()</code> 和 <code>notifyAll()</code> 被定义在 Object 类里？</h3><p>Java 的每个对象中都有一个锁(monitor，也可以成为监视器) 并且 <code>wait()</code>、<code>notify()</code> 等方法用于等待对象的锁或者通知其他线程对象的监视器可用。在 Java 的线程中并没有可供任何对象使用的锁和同步器。这就是为什么这些方法是 Object 类的一部分，这样 Java 的每一个类都有用于线程间通信的基本方法</p><h3 id="为什么-wait-notify-和-notifyall-必须在同步方法或者同步块中被调用" tabindex="-1"><a class="header-anchor" href="#为什么-wait-notify-和-notifyall-必须在同步方法或者同步块中被调用" aria-hidden="true">#</a> 为什么 <code>wait()</code>, <code>notify()</code> 和 <code>notifyAll()</code> 必须在同步方法或者同步块中被调用？</h3><p>当一个线程需要调用对象的 <code>wait()</code> 方法的时候，这个线程必须拥有该对象的锁，接着它就会释放这个对象锁并进入等待状态直到其他线程调用这个对象上的 <code>notify()</code> 方法。同样的，当一个线程需要调用对象的 <code>notify()</code> 方法时，它会释放这个对象的锁，以便其他在等待的线程就可以得到这个对象锁。</p><p>由于所有的这些方法都需要线程持有对象的锁，这样就只能通过同步来实现，所以他们只能在同步方法或者同步块中被调用。</p><h2 id="并发机制的底层实现" tabindex="-1"><a class="header-anchor" href="#并发机制的底层实现" aria-hidden="true">#</a> 并发机制的底层实现</h2>',6),S={href:"https://dunwu.github.io/waterdrop/pages/25767945/",target:"_blank",rel:"noopener noreferrer"},M=c('<h3 id="⭐⭐⭐-synchronized" tabindex="-1"><a class="header-anchor" href="#⭐⭐⭐-synchronized" aria-hidden="true">#</a> ⭐⭐⭐ <code>synchronized</code></h3><blockquote><p><code>synchronized</code> 有什么作用？</p><p><code>synchronized</code> 的原理是什么？</p><p>同步方法和同步块，哪个更好？</p><p>JDK1.6 对<code>synchronized</code> 做了哪些优化？</p><p>使用 <code>synchronized</code> 修饰静态方法和非静态方法有什么区别？</p></blockquote><p><strong>作用</strong></p><p><strong><code>synchronized</code> 可以保证在同一个时刻，只有一个线程可以执行某个方法或者某个代码块</strong>。</p><p><code>synchronized</code> 有 3 种应用方式：</p><ul><li><strong>同步实例方法</strong> - 对于普通同步方法，锁是当前实例对象</li><li><strong>同步静态方法</strong> - 对于静态同步方法，锁是当前类的 <code>Class</code> 对象</li><li><strong>同步代码块</strong> - 对于同步方法块，锁是 <code>synchonized</code> 括号里配置的对象</li></ul><p><strong>原理</strong></p><p><code>synchronized</code> 经过编译后，会在同步块的前后分别形成 <code>monitorenter</code> 和 <code>monitorexit</code> 这两个字节码指令，这两个字节码指令都需要一个引用类型的参数来指明要锁定和解锁的对象。如果 <code>synchronized</code> 明确制定了对象参数，那就是这个对象的引用；如果没有明确指定，那就根据 <code>synchronized</code> 修饰的是实例方法还是静态方法，去对对应的对象实例或 <code>Class</code> 对象来作为锁对象。</p><p><code>synchronized</code> 同步块对同一线程来说是可重入的，不会出现锁死问题。</p><p><code>synchronized</code> 同步块是互斥的，即已进入的线程执行完成前，会阻塞其他试图进入的线程。</p><p><strong>优化</strong></p><p>Java 1.6 以后，<code>synchronized</code> 做了大量的优化，其性能已经与 <code>Lock</code> 、<code>ReadWriteLock</code> 基本上持平。</p><p><code>synchronized</code> 的优化是将锁粒度分为不同级别，<code>synchronized</code> 会根据运行状态动态的由低到高调整锁级别（<strong>偏向锁</strong> -&gt; <strong>轻量级锁</strong> -&gt; <strong>重量级锁</strong>），以减少阻塞。</p><p><strong>同步方法 or 同步块？</strong></p><ul><li>同步块是更好的选择。</li><li>因为它不会锁住整个对象（当然你也可以让它锁住整个对象）。同步方法会锁住整个对象，哪怕这个类中有多个不相关联的同步块，这通常会导致他们停止执行并需要等待获得这个对象上的锁。</li></ul><h3 id="⭐-volatile" tabindex="-1"><a class="header-anchor" href="#⭐-volatile" aria-hidden="true">#</a> ⭐ <code>volatile</code></h3><blockquote><p><code>volatile</code> 有什么作用？</p><p><code>volatile</code> 的原理是什么？</p><p><code>volatile</code> 能代替锁吗？</p><p><code>volatile</code> 和 <code>synchronized</code> 的区别？</p></blockquote><p><strong><code>volatile</code> 无法替代 <code>synchronized</code> ，因为 <code>volatile</code> 无法保证操作的原子性</strong>。</p><p><strong>作用</strong></p><p>被 <code>volatile</code> 关键字修饰的变量有两层含义：</p><ul><li><strong>保证了不同线程对这个变量进行操作时的可见性</strong>，即一个线程修改了某个变量的值，这新值对其他线程来说是立即可见的。</li><li><strong>禁止指令重排序</strong>。</li></ul><p><strong>原理</strong></p><p>观察加入 volatile 关键字和没有加入 volatile 关键字时所生成的汇编代码发现，<strong>加入 <code>volatile</code> 关键字时，会多出一个 <code>lock</code> 前缀指令</strong>。</p><p><strong><code>lock</code> 前缀指令实际上相当于一个内存屏障</strong>（也成内存栅栏），内存屏障会提供 3 个功能：</p><ul><li>它确保指令重排序时不会把其后面的指令排到内存屏障之前的位置，也不会把前面的指令排到内存屏障的后面；即在执行到内存屏障这句指令时，在它前面的操作已经全部完成；</li><li>它会强制将对缓存的修改操作立即写入主存；</li><li>如果是写操作，它会导致其他 CPU 中对应的缓存行无效。</li></ul><p><strong><code>volatile</code> 和 <code>synchronized</code> 的区别？</strong></p><ul><li><code>volatile</code> 本质是在告诉 jvm 当前变量在寄存器（工作内存）中的值是不确定的，需要从主存中读取； <code>synchronized</code> 则是锁定当前变量，只有当前线程可以访问该变量，其他线程被阻塞住。</li><li><code>volatile</code> 仅能使用在变量级别；synchronized 则可以使用在变量、方法、和类级别的。</li><li><code>volatile</code> 仅能实现变量的修改可见性，不能保证原子性；而 <code>synchronized</code> 则可以保证变量的修改可见性和原子性</li><li><code>volatile</code> 不会造成线程的阻塞；synchronized 可能会造成线程的阻塞。</li><li><code>volatile</code> 标记的变量不会被编译器优化；synchronized 标记的变量可以被编译器优化。</li></ul><h3 id="⭐⭐-cas" tabindex="-1"><a class="header-anchor" href="#⭐⭐-cas" aria-hidden="true">#</a> ⭐⭐ CAS</h3><blockquote><p>什么是 CAS？</p><p>CAS 有什么作用？</p><p>CAS 的原理是什么？</p><p>CAS 的三大问题？</p></blockquote><p><strong>作用</strong></p><p><strong>CAS（Compare and Swap）</strong>，字面意思为<strong>比较并交换</strong>。CAS 有 3 个操作数，分别是：内存值 V，旧的预期值 A，要修改的新值 B。当且仅当预期值 A 和内存值 V 相同时，将内存值 V 修改为 B，否则什么都不做。</p><p><strong>原理</strong></p><p>Java 主要利用 <code>Unsafe</code> 这个类提供的 CAS 操作。<code>Unsafe</code> 的 CAS 依赖的是 JV M 针对不同的操作系统实现的 <code>Atomic::cmpxchg</code> 指令。</p><p><strong>三大问题</strong></p><ol><li><strong>ABA 问题</strong>：因为 CAS 需要在操作值的时候检查下值有没有发生变化，如果没有发生变化则更新，但是如果一个值原来是 A，变成了 B，又变成了 A，那么使用 CAS 进行检查时会发现它的值没有发生变化，但是实际上却变化了。ABA 问题的解决思路就是使用版本号。在变量前面追加上版本号，每次变量更新的时候把版本号加一，那么 A－B－A 就会变成 1A-2B－3A。</li><li><strong>循环时间长开销大</strong>。自旋 CAS 如果长时间不成功，会给 CPU 带来非常大的执行开销。如果 JVM 能支持处理器提供的 pause 指令那么效率会有一定的提升，pause 指令有两个作用，第一它可以延迟流水线执行指令（de-pipeline）,使 CPU 不会消耗过多的执行资源，延迟的时间取决于具体实现的版本，在一些处理器上延迟时间是零。第二它可以避免在退出循环的时候因内存顺序冲突（memory order violation）而引起 CPU 流水线被清空（CPU pipeline flush），从而提高 CPU 的执行效率。</li><li><strong>只能保证一个共享变量的原子操作</strong>。当对一个共享变量执行操作时，我们可以使用循环 CAS 的方式来保证原子操作，但是对多个共享变量操作时，循环 CAS 就无法保证操作的原子性，这个时候就可以用锁，或者有一个取巧的办法，就是把多个共享变量合并成一个共享变量来操作。比如有两个共享变量 i ＝ 2,j=a，合并一下 ij=2a，然后用 CAS 来操作 ij。从 Java1.5 开始 JDK 提供了 AtomicReference 类来保证引用对象之间的原子性，你可以把多个变量放在一个对象里来进行 CAS 操作。</li></ol><h3 id="⭐-threadlocal" tabindex="-1"><a class="header-anchor" href="#⭐-threadlocal" aria-hidden="true">#</a> ⭐ <code>ThreadLocal</code></h3><blockquote><p><code>ThreadLocal</code> 有什么作用？</p><p><code>ThreadLocal</code> 的原理是什么？</p><p>如何解决 <code>ThreadLocal</code> 内存泄漏问题？</p></blockquote><p><strong>作用</strong></p><p><strong><code>ThreadLocal</code> 是一个存储线程本地副本的工具类</strong>。</p><p><strong>原理</strong></p><p><code>Thread</code> 类中维护着一个 <code>ThreadLocal.ThreadLocalMap</code> 类型的成员 <code>threadLocals</code>。这个成员就是用来存储当前线程独占的变量副本。</p><p><code>ThreadLocalMap</code> 是 <code>ThreadLocal</code> 的内部类，它维护着一个 <code>Entry</code> 数组， <code>Entry</code> 用于保存键值对，其 key 是 <code>ThreadLocal</code> 对象，value 是传递进来的对象（变量副本）。 <code>Entry</code> 继承了 <code>WeakReference</code> ，所以是弱引用。</p><p><strong>内存泄漏问题</strong></p><p>ThreadLocalMap 的 <code>Entry</code> 继承了 <code>WeakReference</code>，所以它的 key （<code>ThreadLocal</code> 对象）是弱引用，而 value （变量副本）是强引用。</p><ul><li>如果 <code>ThreadLocal</code> 对象没有外部强引用来引用它，那么 <code>ThreadLocal</code> 对象会在下次 GC 时被回收。</li><li>此时，<code>Entry</code> 中的 key 已经被回收，但是 value 由于是强引用不会被垃圾收集器回收。如果创建 <code>ThreadLocal</code> 的线程一直持续运行，那么 value 就会一直得不到回收，产生内存泄露。</li></ul><p>那么如何避免内存泄漏呢？方法就是：<strong>使用 <code>ThreadLocal</code> 的 <code>set</code> 方法后，显示的调用 <code>remove</code> 方法</strong> 。</p><h2 id="内存模型" tabindex="-1"><a class="header-anchor" href="#内存模型" aria-hidden="true">#</a> 内存模型</h2><h3 id="什么是-java-内存模型" tabindex="-1"><a class="header-anchor" href="#什么是-java-内存模型" aria-hidden="true">#</a> 什么是 Java 内存模型</h3><ul><li>Java 内存模型即 Java Memory Model，简称 JMM。JMM 定义了 JVM 在计算机内存(RAM)中的工作方式。JMM 是隶属于 JVM 的。</li><li>并发编程领域两个关键问题：线程间通信和线程间同步</li><li>线程间通信机制 <ul><li>共享内存 - 线程间通过写-读内存中的公共状态来隐式进行通信。</li><li>消息传递 - java 中典型的消息传递方式就是 wait()和 notify()。</li></ul></li><li>线程间同步机制 <ul><li>在共享内存模型中，必须显示指定某个方法或某段代码在线程间互斥地执行。</li><li>在消息传递模型中，由于发送消息必须在接收消息之前，因此同步是隐式进行的。</li></ul></li><li>Java 的并发采用的是共享内存模型</li><li>JMM 决定一个线程对共享变量的写入何时对另一个线程可见。</li><li>线程之间的共享变量存储在主内存（main memory）中，每个线程都有一个私有的本地内存（local memory），本地内存中存储了该线程以读/写共享变量的副本。</li><li>JMM 把内存分成了两部分：线程栈区和堆区 <ul><li>线程栈 <ul><li>JVM 中运行的每个线程都拥有自己的线程栈，线程栈包含了当前线程执行的方法调用相关信息，我们也把它称作调用栈。随着代码的不断执行，调用栈会不断变化。</li><li>线程栈还包含了当前方法的所有本地变量信息。线程中的本地变量对其它线程是不可见的。</li></ul></li><li>堆区 <ul><li>堆区包含了 Java 应用创建的所有对象信息，不管对象是哪个线程创建的，其中的对象包括原始类型的封装类（如 Byte、Integer、Long 等等）。不管对象是属于一个成员变量还是方法中的本地变量，它都会被存储在堆区。</li></ul></li><li>一个本地变量如果是原始类型，那么它会被完全存储到栈区。</li><li>一个本地变量也有可能是一个对象的引用，这种情况下，这个本地引用会被存储到栈中，但是对象本身仍然存储在堆区。</li><li>对于一个对象的成员方法，这些方法中包含本地变量，仍需要存储在栈区，即使它们所属的对象在堆区。</li><li>对于一个对象的成员变量，不管它是原始类型还是包装类型，都会被存储到堆区。</li></ul></li></ul><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/cs/java/javacore/concurrent/java-memory-model_3.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure>',50),L={href:"https://blog.csdn.net/suifeng3051/article/details/52611310",target:"_blank",rel:"noopener noreferrer"},R=e("h2",{id:"同步容器和并发容器",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#同步容器和并发容器","aria-hidden":"true"},"#"),o(" 同步容器和并发容器")],-1),q={href:"https://dunwu.github.io/waterdrop/pages/6fd8d836/",target:"_blank",rel:"noopener noreferrer"},F=c('<h3 id="⭐-同步容器" tabindex="-1"><a class="header-anchor" href="#⭐-同步容器" aria-hidden="true">#</a> ⭐ 同步容器</h3><blockquote><p>什么是同步容器？</p><p>有哪些常见同步容器？</p><p>它们是如何实现线程安全的？</p><p>同步容器真的线程安全吗？</p></blockquote><p><strong>类型</strong></p><p><code>Vector</code>、<code>Stack</code>、<code>Hashtable</code></p><p><strong>作用/原理</strong></p><p>同步容器的同步原理就是在方法上用 <code>synchronized</code> 修饰。 <strong><code>synchronized</code> 可以保证在同一个时刻，只有一个线程可以执行某个方法或者某个代码块</strong>。</p><p><code>synchronized</code> 的互斥同步会产生阻塞和唤醒线程的开销。显然，这种方式比没有使用 <code>synchronized</code> 的容器性能要差。</p><p><strong>线程安全</strong></p><p>同步容器真的绝对安全吗？</p><p>其实也未必。在做复合操作（非原子操作）时，仍然需要加锁来保护。常见复合操作如下：</p><ul><li><strong>迭代</strong>：反复访问元素，直到遍历完全部元素；</li><li><strong>跳转</strong>：根据指定顺序寻找当前元素的下一个（下 n 个）元素；</li><li><strong>条件运算</strong>：例如若没有则添加等；</li></ul><h3 id="⭐⭐⭐-concurrenthashmap" tabindex="-1"><a class="header-anchor" href="#⭐⭐⭐-concurrenthashmap" aria-hidden="true">#</a> ⭐⭐⭐ ConcurrentHashMap</h3><blockquote><p>请描述 ConcurrentHashMap 的实现原理？</p><p>ConcurrentHashMap 为什么放弃了分段锁？</p></blockquote><p>基础数据结构原理和 <code>HashMap</code> 一样，JDK 1.7 采用 数组＋单链表；JDK 1.8 采用数组＋单链表＋红黑树。</p><p>并发安全特性的实现：</p><p>JDK 1.7：</p><ul><li>使用分段锁，设计思路是缩小锁粒度，提高并发吞吐。</li><li>写数据时，会使用可重入锁去锁住分段（segment）。</li></ul><p>JDK 1.8：</p><ul><li>取消分段锁，直接采用 <code>transient volatile HashEntry&lt;K,V&gt;[] table</code> 保存数据，采用 table 数组元素作为锁，从而实现了对每一行数据进行加锁，进一步减少并发冲突的概率。</li><li>写数据时，使用是 CAS + <code>synchronized</code>。 <ul><li>根据 key 计算出 hashcode 。</li><li>判断是否需要进行初始化。</li><li><code>f</code> 即为当前 key 定位出的 Node，如果为空表示当前位置可以写入数据，利用 CAS 尝试写入，失败则自旋保证成功。</li><li>如果当前位置的 <code>hashcode == MOVED == -1</code>,则需要进行扩容。</li><li>如果都不满足，则利用 synchronized 锁写入数据。</li><li>如果数量大于 <code>TREEIFY_THRESHOLD</code> 则要转换为红黑树。</li></ul></li></ul>',19);function E(V,U){const d=r("ExternalLinkIcon");return i(),t("div",null,[s,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",h,[o("Java"),p,o(" Methods and "),u,o(" States"),l(d)]),g,o(" 👉 参考阅读："),e("a",b,[o("Java 线程的 5 种状态及切换(透彻讲解)"),l(d)])])]),f,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",v,[o("Java 创建线程的三种方式及其对比"),l(d)])])]),y,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",_,[o("Java 并发编程：Callable、Future 和 FutureTask"),l(d)])])]),k,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",m,[o("Java 线程中 yield 与 join 方法的区别"),l(d)]),C,o(" 👉 参考阅读："),e("a",T,[o("sleep()，wait()，yield()和 join()方法的区别"),l(d)])])]),J,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",x,[o("Java 中守护线程的总结"),l(d)])])]),w,j,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",A,[o("Java 并发编程：线程间协作的两种方式：wait、notify、notifyAll 和 Condition"),l(d)])])]),z,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",S,[o("Java 并发核心机制"),l(d)])])]),M,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",L,[o("全面理解 Java 内存模型"),l(d)])])]),R,e("blockquote",null,[e("p",null,[o("👉 参考阅读："),e("a",q,[o("Java 并发容器"),l(d)])])]),F])}const P=a(n,[["render",E],["__file","index.html.vue"]]);export{P as default};
